  },
  "components": {
    "schemas": {
      "UserSnippet": {
        "type": "object",
        "description": "Basic user information snippet",
        "properties": {
          "user_id": {
            "type": "string",
            "description": "Unique identifier for the user",
            "example": "user_789"
          },
          "username": {
            "type": "string",
            "description": "User's display name or handle",
            "example": "naturelover"
          }
        },
        "required": ["user_id", "username"]
      },
      "Comment": {
        "type": "object",
        "description": "A comment on a post",
        "properties": {
          "comment_id": {
            "type": "string",
            "description": "Unique identifier for the comment",
            "example": "comm_101"
          },
          "author": {
            "$ref": "#/components/schemas/UserSnippet"
          },
          "text": {
            "type": "string",
            "description": "Text content of the comment",
            "example": "Looks amazing! Wish I was there."
          },
          "posted_at": {
            "type": "string",
            "format": "date-time",
            "description": "Timestamp when the comment was posted",
            "example": "2024-06-15T15:00:00Z"
          }
        },
        "required": ["comment_id", "author", "text", "posted_at"]
      },
      "Post": {
        "type": "object",
        "description": "A social media post by the user",
        "properties": {
          "post_id": {
            "type": "string",
            "description": "Unique identifier for the post",
            "example": "post_456"
          },
          "content": {
            "type": "string",
            "description": "Text content of the post",
            "example": "Enjoying the sunny day at the beach!"
          },
          "created_at": {
            "type": "string",
            "format": "date-time",
            "description": "Timestamp when the post was created",
            "example": "2024-06-15T14:23:00Z"
          },
          "comments": {
            "type": "array",
            "description": "List of comments on the post",
            "items": {
              "$ref": "#/components/schemas/Comment"
            }
          },
          "liked_by": {
            "type": "array",
            "description": "List of users who liked the post",
            "items": {
              "$ref": "#/components/schemas/UserSnippet"
            }
          }
        },
        "required": ["post_id", "content", "created_at", "comments", "liked_by"]
      },
      "UserFeedResponse": {
        "type": "object",
        "description": "User feed containing posts with comments and likes",
        "properties": {
          "user_id": {
            "type": "string",
            "description": "Unique identifier for the user requesting the feed",
            "example": "user_789"
          },
          "posts": {
            "type": "array",
            "description": "List of posts in the user feed",
            "items": {
              "$ref": "#/components/schemas/Post"
            }
          }
        },
        "required": ["user_id", "posts"]
      }
    }
  }
}

