{
  "openapi": "3.0.0",
  "info": {
    "title": "Resposta de Pedido de E-commerce",
    "version": "1.0.0"
  },
  "components": {
    "schemas": {
      "Item": {
        "type": "object",
        "description": "Informações de um item físico no pedido",
        "properties": {
          "product_id": {
            "type": "string",
            "description": "Identificador único do produto",
            "example": "prod_001"
          },
          "name": {
            "type": "string",
            "description": "Nome do produto",
            "example": "Smartphone XYZ"
          },
          "quantity": {
            "type": "integer",
            "description": "Quantidade do item no pedido",
            "example": 2
          },
          "price": {
            "type": "number",
            "format": "float",
            "description": "Preço unitário do produto em moeda local",
            "example": 1999.9
          },
          "weight_kg": {
            "type": "number",
            "format": "float",
            "description": "Peso do item em quilogramas",
            "example": 0.18
          }
        },
        "required": ["product_id", "name", "quantity", "price", "weight_kg"]
      },
      "Address": {
        "type": "object",
        "description": "Endereço de entrega do pedido",
        "properties": {
          "recipient_name": {
            "type": "string",
            "description": "Nome da pessoa que receberá o pedido",
            "example": "João Silva"
          },
          "street": {
            "type": "string",
            "description": "Nome e número da rua",
            "example": "Rua das Flores, 123"
          },
          "city": {
            "type": "string",
            "description": "Cidade do endereço",
            "example": "Belo Horizonte"
          },
          "state": {
            "type": "string",
            "description": "Estado ou região",
            "example": "MG"
          },
          "zip": {
            "type": "string",
            "description": "Código postal (CEP)",
            "example": "30123-456"
          },
          "country": {
            "type": "string",
            "description": "País do endereço",
            "example": "Brasil"
          }
        },
        "required": ["recipient_name", "street", "city", "state", "zip", "country"]
      },
      "Payment": {
        "type": "object",
        "description": "Detalhes da transação de pagamento",
        "properties": {
          "transaction_id": {
            "type": "string",
            "description": "Identificador único da transação",
            "example": "txn_78910"
          },
          "method": {
            "type": "string",
            "description": "Método de pagamento utilizado",
            "example": "credit_card"
          },
          "amount": {
            "type": "number",
            "format": "float",
            "description": "Valor pago",
            "example": 4499.3
          },
          "currency": {
            "type": "string",
            "description": "Moeda da transação",
            "example": "BRL"
          },
          "status": {
            "type": "string",
            "description": "Status atual da transação de pagamento",
            "example": "approved"
          }
        },
        "required": ["transaction_id", "method", "amount", "currency", "status"]
      },
      "LinkObject": {
        "type": "object",
        "description": "Objeto padrão HAL para links",
        "properties": {
          "href": {
            "type": "string",
            "format": "uri",
            "description": "URL do recurso",
            "example": "https://api.store.com/orders/order_12345"
          }
        },
        "required": ["href"]
      },
      "Links": {
        "type": "object",
        "description": "Coleção de links HAL associados ao pedido",
        "properties": {
          "self": { "$ref": "#/components/schemas/LinkObject" },
          "tracking": { "$ref": "#/components/schemas/LinkObject" }
        },
        "required": ["self", "tracking"]
      },
      "OrderResponse": {
        "type": "object",
        "description": "Resposta contendo informações completas do pedido",
        "properties": {
          "order_id": {
            "type": "string",
            "description": "Identificador único do pedido",
            "example": "order_12345"
          },
          "items": {
            "type": "array",
            "description": "Lista de itens físicos no pedido",
            "items": {
              "$ref": "#/components/schemas/Item"
            },
            "example": [
              {
                "product_id": "prod_001",
                "name": "Smartphone XYZ",
                "quantity": 2,
                "price": 1999.9,
                "weight_kg": 0.18
              },
              {
                "product_id": "prod_002",
                "name": "Bluetooth Headphones",
                "quantity": 1,
                "price": 499.5,
                "weight_kg": 0.25
              }
            ]
          },
          "shipping_address": {
            "$ref": "#/components/schemas/Address"
          },
          "payment": {
            "$ref": "#/components/schemas/Payment"
          },
          "_links": {
            "$ref": "#/components/schemas/Links"
          }
        },
        "required": ["order_id", "items", "shipping_address", "payment", "_links"]
      }
    }
  }
}

