}).openapi({ description: 'Customer details including dietary needs' });

const PreOrderItemSchema = z.object({
  item_id: z.string().openapi({ description: 'Unique identifier for the menu item', example: 'itm_001' }),
  name: z.string().openapi({ description: 'Name of the dish', example: 'Truffle Risotto' }),
  quantity: z.number().int().positive().openapi({ description: 'Number of portions ordered', example: 2 })
}).openapi({ description: 'Individual pre-ordered menu item' });

export const ReservationResponseSchema = z.object({
  reservation_id: z.string().openapi({ description: 'Unique identifier for the reservation', example: 'res_9982' }),
  table_number: z.number().int().positive().openapi({ description: 'Assigned table number in the restaurant', example: 12 }),
  customer: CustomerSchema,
  pre_ordered_items: z.array(PreOrderItemSchema).openapi({ description: 'List of items ordered in advance' })
