});

import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const UserSnippetSchema = z.object({
  user_id: z.string().openapi({ description: 'Unique identifier for the user', example: 'usr_001' }),
  username: z.string().optional().openapi({ description: 'Unique handle of the user', example: 'dev_guru' }),
  display_name: z.string().optional().openapi({ description: 'Public display name of the user', example: 'Alice' })
}).openapi({ description: 'Minimal user information snippet' });

const CommentSchema = z.object({
  comment_id: z.string().openapi({ description: 'Unique identifier for the comment', example: 'cmt_101' }),
  text: z.string().openapi({ description: 'The content of the comment', example: 'Great insights!' }),
  user_id: z.string().openapi({ description: 'ID of the user who authored the comment', example: 'usr_002' })
}).openapi({ description: 'Individual comment entity' });

const PostSchema = z.object({
  post_id: z.string().openapi({ description: 'Unique identifier for the post', example: 'pst_8829' }),
  content: z.string().openapi({ description: 'The main text content of the post', example: 'Exploring the new features of TypeScript 5.x!' }),
  author: UserSnippetSchema.omit({ display_name: true }),
  comments: z.array(CommentSchema).openapi({ description: 'List of comments on the post' }),
  likes: z.array(UserSnippetSchema.omit({ username: true })).openapi({ description: 'List of users who liked the post' })
}).openapi({ description: 'Complete post object with nested interactions' });

const PaginationSchema = z.object({
  next_cursor: z.string().nullable().openapi({ description: 'Cursor for the next page of results', example: 'c_99283' }),
  limit: z.number().openapi({ description: 'Number of items returned in this batch', example: 10 })
}).openapi({ description: 'Pagination control object' });

export const FeedResponseSchema = z.object({
  feed: z.array(PostSchema).openapi({ description: 'Array of posts in the user feed' }),
  pagination: PaginationSchema
}).openapi({ title: 'User Feed Response', description: 'Paginated response containing user posts with nested comments and likes' });

