import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const AddressSchema = z.object({
  street: z.string().openapi({ description: 'Nome da rua e número do endereço', example: 'Rua das Indústrias, 450' }),
  city: z.string().openapi({ description: 'Cidade do endereço', example: 'Belo Horizonte' }),
  state: z.string().openapi({ description: 'Estado ou província', example: 'MG' }),
  postal_code: z.string().openapi({ description: 'Código postal ou CEP', example: '30123-456' }),
  country: z.string().openapi({ description: 'País de destino', example: 'Brasil' }),
}).openapi({ title: 'Endereço', description: 'Estrutura de endereço para cobrança ou entrega' });

const CompanyProfileSchema = z.object({
  company_name: z.string().openapi({ description: 'Razão social da empresa compradora', example: 'Distribuidora de Metais S.A.' }),
  tax_id: z.string().openapi({ description: 'Identificador fiscal da empresa (ex: CNPJ)', example: '45.678.901/0001-22' }),
  contact_email: z.string().email().openapi({ description: 'E-mail de contato para comunicações financeiras', example: 'financeiro@distrimetais.com.br' }),
  billing_address: AddressSchema,
}).openapi({ title: 'Perfil do Comprador', description: 'Informações cadastrais da empresa cliente' });

const DiscountTierSchema = z.object({
  tier_name: z.string().openapi({ description: 'Nome da faixa de desconto aplicada', example: 'Volume Bronze (1k-5k)' }),
  percentage: z.number().min(0).max(100).openapi({ description: 'Percentual de desconto aplicado nesta faixa', example: 5.0 }),
  amount_saved: z.number().openapi({ description: 'Valor monetário economizado com este desconto específico', example: 212.50 }),
}).openapi({ title: 'Faixa de Desconto', description: 'Detalhes de um nível de desconto por volume' });

const LineItemSchema = z.object({
  sku: z.string().openapi({ description: 'Código de identificação do produto (SKU)', example: 'STL-BOLT-M12' }),
  product_name: z.string().openapi({ description: 'Nome descritivo do item', example: 'Parafuso Sextavado M12 - Aço Carbono' }),
  quantity: z.number().int().positive().openapi({ description: 'Quantidade de unidades solicitadas', example: 5000 }),
  unit_price: z.number().positive().openapi({ description: 'Preço unitário do produto antes dos descontos', example: 0.85 }),
  discounts: z.array(DiscountTierSchema).openapi({ description: 'Lista de descontos aplicados ao item baseados em volume' }),
  subtotal: z.number().openapi({ description: 'Valor total do item após a aplicação de todos os descontos', example: 4027.50 }),
}).openapi({ title: 'Item da Fatura', description: 'Detalhes de um produto individual no pedido' });

const ShippingTermsSchema = z.object({
  carrier: z.string().openapi({ description: 'Nome da empresa transportadora responsável', example: 'Transportadora Rápida Log' }),
  method: z.string().openapi({ description: 'Método de transporte utilizado', example: 'Freight Truck' }),
  shipping_cost: z.number().nonnegative().openapi({ description: 'Custo total do frete e logística', example: 350.00 }),
  incoterms: z.string().openapi({ description: 'Termos internacionais de comércio aplicados', example: 'FOB' }),
}).openapi({ title: 'Termos de Frete', description: 'Condições de envio e logística' });

const TotalsSchema = z.object({
  gross_amount: z.number().openapi({ description: 'Valor bruto total de todos os itens antes de descontos e impostos', example: 4800.00 }),
  total_discount: z.number().openapi({ description: 'Soma total de todos os descontos aplicados na fatura', example: 372.50 }),
  tax_amount: z.number().openapi({ description: 'Valor total de impostos incidentes sobre a venda', example: 520.00 }),
  net_amount: z.number().openapi({ description: 'Valor líquido final a ser pago pelo cliente', example: 4947.50 }),
}).openapi({ title: 'Resumo de Totais', description: 'Consolidado financeiro da fatura' });

export const WholesaleInvoiceSchema = z.object({
  invoice_id: z.string().openapi({ description: 'Identificador único da fatura de atacado', example: 'INV-2023-88421' }),
  issue_date: z.string().datetime().openapi({ description: 'Data e hora de emissão da fatura', example: '2023-11-15T09:30:00Z' }),
  due_date: z.string().datetime().openapi({ description: 'Data e hora de vencimento do pagamento', example: '2023-12-15T23:59:59Z' }),
  buyer_profile: CompanyProfileSchema,
  line_items: z.array(LineItemSchema).openapi({ description: 'Lista de produtos e quantidades incluídos no pedido' }),
  shipping_details: ShippingTermsSchema,
  totals: TotalsSchema,
}).openapi({ title: 'Fatura de Atacado B2B', description: 'Documento detalhado de cobrança para vendas corporativas de grande volume' });

