const AffectedAssetSchema = z.object({
  ip_address: z.string().ip().openapi({ description: 'The IPv4 or IPv6 address of the compromised asset', example: '192.168.1.45' }),
  hostname: z.string().openapi({ description: 'The network hostname of the affected machine', example: 'prod-web-server-01' }),
  location: z.string().openapi({ description: 'Physical or cloud region where the asset is located', example: 'US-East-1' }),
  risk_score: z.number().min(0).max(10).openapi({ description: 'Calculated risk score from 0 to 10', example: 9.8 })
}).openapi({ description: 'Details of a specific network asset affected by the threat' });

const MitigationProtocolSchema = z.object({
  step_id: z.number().int().openapi({ description: 'Sequential order of the mitigation step', example: 1 }),
  action: z.string().openapi({ description: 'Detailed instruction for the security responder', example: 'Isolate affected hosts from the internal network' }),
  priority: z.string().openapi({ description: 'Urgency level of the specific action', example: 'Immediate' }),
