  confidence_level: z.number().min(0).max(1).openapi({ description: 'Probability that the alert is a true positive (0.0 to 1.0)', example: 0.95 }),
  tags: z.array(z.string()).openapi({ description: 'Categorization tags for the threat actor or malware family', example: ['APT28', 'CobaltStrike'] })
