  alert_id: z.string().openapi({ description: 'Unique identifier for the threat alert', example: 'THREAT-2023-9901-X' }),
  timestamp: z.string().datetime().openapi({ description: 'ISO 8601 timestamp of when the alert was triggered', example: '2023-10-27T14:22:01Z' }),
  severity: SeverityEnum,
  threat_type: z.string().openapi({ description: 'Classification of the threat (e.g., Ransomware, Phishing)', example: 'Ransomware C2 Communication' }),
  affected_assets: z.array(AffectedAssetSchema).openapi({ description: 'List of all network assets identified as compromised or targeted' }),
