{
  "openapi": "3.0.0",
  "info": {
    "title": "Government Tax Return Assessment Response",
    "version": "1.0.0"
  },
  "components": {
    "schemas": {
      "Citizen": {
        "type": "object",
        "description": "Details of the citizen filing the tax return",
        "properties": {
          "citizen_id": {
            "type": "string",
            "description": "Unique identifier for the citizen",
            "example": "cit_12345"
          },
          "full_name": {
            "type": "string",
            "description": "Full name of the citizen",
            "example": "John Doe"
          }
        },
        "required": ["citizen_id", "full_name"]
      },
      "DeductionDetail": {
        "type": "object",
        "description": "Detail item related to a specific deduction",
        "properties": {
          "provider": {
            "type": "string",
            "description": "Provider of the service or insurance associated with the deduction",
            "example": "HealthCare Plus"
          },
          "policy_number": {
            "type": "string",
            "description": "Policy number for insurance or service",
            "example": "HP-456789"
          },
          "institution": {
            "type": "string",
            "description": "Educational institution for education related deductions",
            "example": "State University"
          },
          "course": {
            "type": "string",
            "description": "Course name if deduction relates to education",
            "example": "MBA"
          },
          "year": {
            "type": "integer",
            "description": "Year of the course or related service",
            "example": 2023
          }
        },
        "oneOf": [
          {
            "required": ["provider", "policy_number"]
          },
          {
            "required": ["institution", "course", "year"]
          }
        ]
      },
      "Deduction": {
        "type": "object",
        "description": "Valid deduction claimed in the tax return",
        "properties": {
          "deduction_type": {
            "type": "string",
            "description": "Type of the deduction",
            "example": "Health Insurance"
          },
          "amount": {
            "type": "number",
            "format": "float",
            "description": "Amount claimed as deduction",
            "example": 3000.00
          },
          "details": {
            "type": "array",
            "description": "Detailed items for the deduction",
            "items": {
              "$ref": "#/components/schemas/DeductionDetail"
            }
          }
        },
        "required": ["deduction_type", "amount", "details"]
      },
      "FinalAssessment": {
        "type": "object",
        "description": "Final tax calculation results after deductions and payments",
        "properties": {
          "tax_due": {
            "type": "number",
            "format": "float",
            "description": "Total tax due before payments",
            "example": 5000.00
          },
          "tax_paid": {
            "type": "number",
            "format": "float",
            "description": "Total tax amount already paid by the citizen",
            "example": 6500.00
          },
          "refund_amount": {
            "type": "number",
            "format": "float",
            "description": "Tax refund amount if tax_paid is greater than tax_due",
            "example": 1500.00
          },
          "debt_amount": {
            "type": "number",
            "format": "float",
            "description": "Tax debt amount if tax_due exceeds tax_paid",
            "example": 0.00
          }
        },
        "required": ["tax_due", "tax_paid", "refund_amount", "debt_amount"]
      },
      "TaxReturnAssessmentResponse": {
        "type": "object",
        "description": "Government tax return assessment response detailing declared income, deductions, and final tax calculations",
        "properties": {
          "tax_return_id": {
            "type": "string",
            "description": "Unique identifier for the tax return",
            "example": "tr_987654"
          },
          "citizen": {
            "$ref": "#/components/schemas/Citizen"
          },
          "declared_income": {
            "type": "number",
            "format": "float",
            "description": "Declared taxable income for the citizen",
            "example": 75000.00
          },
          "deductions": {
            "type": "array",
            "description": "Array of valid deductions claimed",
            "items": {
              "$ref": "#/components/schemas/Deduction"
            }
          },
          "final_assessment": {
            "$ref": "#/components/schemas/FinalAssessment"
          }
        },
        "required": ["tax_return_id", "citizen", "declared_income", "deductions", "final_assessment"]
      }
    }
  }
}

