import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const CoordinatesSchema = z.object({
  lat: z.number().openapi({ description: 'Latitude da localização', example: -23.96 }),
  lng: z.number().openapi({ description: 'Longitude da localização', example: -46.33 })
}).openapi({ description: 'Coordenadas geográficas' });

const PortLocationSchema = z.object({
  port_code: z.string().openapi({ description: 'Código UN/LOCODE do porto', example: 'BRSSZ' }),
  port_name: z.string().openapi({ description: 'Nome do porto', example: 'Porto de Santos' }),
  coordinates: CoordinatesSchema
}).openapi({ description: 'Dados de localização do porto' });

const CustomsStatusSchema = z.object({
  clearance_id: z.string().openapi({ description: 'ID do processo de desembaraço', example: 'CUST-445' }),
  status: z.enum(['pending', 'cleared', 'inspected', 'rejected']).openapi({ description: 'Status atual da alfândega', example: 'cleared' }),
  cleared_at: z.string().datetime().openapi({ description: 'Data e hora da liberação', example: '2023-10-27T10:00:00Z' })
}).openapi({ description: 'Status do desembaraço aduaneiro' });

const EnvironmentalReadingSchema = z.object({
  timestamp: z.string().datetime().openapi({ description: 'Momento da leitura', example: '2023-10-27T08:00:00Z' }),
  temperature: z.number().openapi({ description: 'Temperatura em graus Celsius', example: 4.5 }),
  humidity: z.number().openapi({ description: 'Percentual de umidade relativa', example: 65 })
}).openapi({ description: 'Leitura de sensores ambientais' });

export const ContainerTrackingSchema = z.object({
  container_id: z.string().openapi({ description: 'Identificador único do contêiner', example: 'CONT-99821-X' }),
  current_location: PortLocationSchema,
  customs_status: CustomsStatusSchema,
  environmental_readings: z.array(EnvironmentalReadingSchema).openapi({ description: 'Histórico de leituras ambientais' })
}).openapi({ title: 'Rastreamento de Contêiner', description: 'Resposta detalhada contendo localização, status aduaneiro e telemetria ambiental' });

import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const TaxpayerSchema = z.object({
  tax_id: z.string().openapi({ description: 'The unique government-issued tax identification number', example: '992-11-4455' }),
  full_name: z.string().openapi({ description: 'The legal full name of the taxpayer', example: 'Alexander J. Sterling' }),
  residency_status: z.enum(['resident', 'non-resident']).openapi({ description: 'The tax residency classification of the individual', example: 'resident' }),
  filing_status: z.enum(['single', 'married_joint', 'married_separate', 'head_of_household']).openapi({ description: 'The legal filing status for the tax year', example: 'single' })
}).openapi({ title: 'Taxpayer Information', description: 'Personal details of the individual filing the return' });

const IncomeSummarySchema = z.object({
  gross_annual_income: z.number().openapi({ description: 'Total combined income before any deductions or taxes', example: 145000.00 }),
  employment_income: z.number().openapi({ description: 'Income derived from wages, salaries, and tips', example: 130000.00 }),
  investment_income: z.number().openapi({ description: 'Income from dividends, interest, and capital gains', example: 12500.00 }),
  business_income: z.number().openapi({ description: 'Net income from self-employment or business ownership', example: 2500.00 }),
  other_income: z.number().openapi({ description: 'Miscellaneous income from other sources', example: 0.00 })
}).openapi({ title: 'Income Summary', description: 'Breakdown of all income sources reported' });

const DeductionSchema = z.object({
  category: z.enum(['medical', 'charity', 'education', 'mortgage', 'retirement']).openapi({ description: 'The classification of the deduction type', example: 'medical' }),
  amount: z.number().openapi({ description: 'The monetary value of the deduction', example: 4200.50 }),
  description: z.string().openapi({ description: 'A brief explanation of the deduction purpose', example: 'Unreimbursed medical expenses' }),
  documentation_ref: z.string().openapi({ description: 'Reference ID for the supporting document in the government database', example: 'MED-2023-001' })
}).openapi({ title: 'Deduction Item', description: 'Details of a single valid tax deduction' });

const TaxCalculationSchema = z.object({
  total_tax_liability: z.number().openapi({ description: 'The total tax owed before credits and deductions', example: 28500.00 }),
  total_deductions_applied: z.number().openapi({ description: 'The sum of all valid deductions applied to the gross income', example: 8700.50 }),
  total_tax_credits: z.number().openapi({ description: 'The total value of tax credits applied to reduce liability', example: 5200.00 }),
  net_tax_amount: z.number().openapi({ description: 'The final calculated amount. Negative values indicate a refund, positive indicate debt', example: -1500.50 }),
  final_status: z.enum(['REFUND', 'DEBT', 'ZERO']).openapi({ description: 'The final outcome of the assessment', example: 'REFUND' })
}).openapi({ title: 'Tax Calculation Result', description: 'The mathematical summary of the tax assessment' });

export const TaxAssessmentResponseSchema = z.object({
  assessment_id: z.string().openapi({ description: 'Unique identifier for this specific assessment transaction', example: 'TAX-2023-8842-X9' }),
  timestamp: z.string().datetime().openapi({ description: 'The ISO 8601 timestamp when the assessment was finalized', example: '2023-11-20T10:15:30Z' }),
  taxpayer: TaxpayerSchema,
  income_summary: IncomeSummarySchema,
  deductions: z.array(DeductionSchema).openapi({ description: 'A list of all verified deductions', example: [] }),
  tax_calculation: TaxCalculationSchema
}).openapi({ title: 'Tax Assessment Response', description: 'The complete response object for a government tax return assessment' });

