const PatientDemographicsSchema = z.object({
  patient_id: z.string().openapi({ description: 'Unique identifier for the patient', example: 'PAT-99283' }),
  full_name: z.string().openapi({ description: 'The legal full name of the patient', example: 'Johnathan Doe' }),
  date_of_birth: z.string().openapi({ description: 'Patient date of birth in ISO 8601 format', example: '1985-05-12' }),
  gender: z.enum(['Male', 'Female', 'Other', 'Unknown']).openapi({ description: 'Biological gender of the patient', example: 'Male' })
}).openapi({ title: 'Patient Demographics', description: 'Personal identification details of the patient' });

const ReferenceRangeSchema = z.object({
  min: z.number().openapi({ description: 'Minimum value of the normal range', example: 70 }),
  max: z.number().openapi({ description: 'Maximum value of the normal range', example: 99 }),
  unit: z.string().openapi({ description: 'The unit of measurement for the range', example: 'mg/dL' })
}).openapi({ title: 'Reference Range', description: 'The physiological normal bounds for a biomarker' });

const BiomarkerSchema = z.object({
  biomarker_id: z.string().openapi({ description: 'Unique identifier for the specific biomarker test', example: 'BM-001' }),
  name: z.string().openapi({ description: 'Common name of the biomarker', example: 'Glucose' }),
  value: z.number().openapi({ description: 'The measured value of the biomarker', example: 95.5 }),
  unit: z.string().openapi({ description: 'The unit of measurement for the result', example: 'mg/dL' }),
