const PathologistSignatureSchema = z.object({
  pathologist_id: z.string().openapi({ description: 'Unique identifier for the reviewing pathologist', example: 'DOC-441' }),
  name: z.string().openapi({ description: 'Full name of the pathologist', example: 'Dr. Sarah Smith' }),
  timestamp: z.string().openapi({ description: 'ISO 8601 timestamp of the digital signature', example: '2023-10-27T10:00:00Z' }),
  digital_hash: z.string().openapi({ description: 'Cryptographic hash verifying the integrity of the report', example: 'sha256:e3b0c442...' })
