        "type": "object",
        "description": "Metadata information about the playlist",
        "properties": {
          "playlist_id": {
            "type": "string",
            "description": "Unique identifier of the playlist",
            "example": "pl_987654"
          },
          "title": {
            "type": "string",
            "description": "Title of the playlist",
            "example": "Summer Chill Vibes"
          },
          "description": {
            "type": "string",
            "description": "Description of the playlist",
            "example": "A collection of relaxing summer tunes to unwind"
          },
          "created_at": {
            "type": "string",
            "format": "date-time",
            "description": "ISO 8601 creation timestamp",
            "example": "2024-04-01T10:00:00Z"
