          "updated_at": {
            "type": "string",
            "format": "date-time",
            "description": "ISO 8601 last update timestamp",
            "example": "2024-05-15T15:30:00Z"
          },
          "creator": {
            "$ref": "#/components/schemas/UserSnippet"
          }
        },
        "required": ["playlist_id", "title", "description", "created_at", "updated_at", "creator"]
      },
      "Pagination": {
        "type": "object",
        "description": "Pagination details for playlist tracks",
