const ISBNMetadataSchema = z.object({
  isbn_10: z.string().openapi({ description: 'The 10-digit International Standard Book Number', example: '020161622X' }),
  isbn_13: z.string().openapi({ description: 'The 13-digit International Standard Book Number', example: '978-0201616224' }),
  publisher: z.string().openapi({ description: 'The name of the publishing house', example: 'Addison-Wesley Professional' }),
  publication_year: z.number().int().openapi({ description: 'The year the book was published', example: 1999 })
}).openapi({ description: 'Standardized ISBN and publishing metadata' });

const ShelfLocationSchema = z.object({
  section: z.string().openapi({ description: 'The library section name', example: 'Technology' }),
  row: z.string().openapi({ description: 'The specific row identifier', example: 'T-12' }),
  shelf: z.string().openapi({ description: 'The specific shelf identifier', example: 'B-4' })
}).openapi({ description: 'Physical coordinates of a book within the library' });

const PhysicalCopySchema = z.object({
  copy_id: z.string().openapi({ description: 'Unique identifier for the physical copy', example: 'cp_001' }),
