}).openapi({ description: 'Details of a specific physical book instance' });

const DigitalAvailabilitySchema = z.object({
  is_available: z.boolean().openapi({ description: 'Whether the digital version is currently available for borrowing', example: true }),
  formats: z.array(z.string()).openapi({ description: 'Available digital file formats', example: ['PDF', 'EPUB'] }),
  license_type: z.string().openapi({ description: 'The type of digital license held by the library', example: 'Institutional' }),
  access_url: z.string().url().openapi({ description: 'URL to access the digital resource', example: 'https://lib.example.com/digital/bk_98234' })
}).openapi({ description: 'Digital borrowing and access information' });

const BookSchema = z.object({
  book_id: z.string().openapi({ description: 'Unique internal library identifier for the book', example: 'bk_98234' }),
  title: z.string().openapi({ description: 'Full title of the book', example: 'The Pragmatic Programmer' }),
  authors: z.array(z.string()).openapi({ description: 'List of authors who wrote the book', example: ['Andrew Hunt', 'David Thomas'] }),
  isbn_metadata: ISBNMetadataSchema,
  genre: z.string().openapi({ description: 'The primary genre or category of the book', example: 'Software Engineering' }),
  physical_copies: z.array(PhysicalCopySchema).openapi({ description: 'List of all physical copies owned by the library' }),
  digital_availability: DigitalAvailabilitySchema
}).openapi({ description: 'Comprehensive book entity including physical and digital status' });

const SearchMetaSchema = z.object({
  total_hits: z.number().int().openapi({ description: 'Total number of books matching the search criteria', example: 1 }),
