  execution_time_ms: z.number().int().openapi({ description: 'Time taken to process the search in milliseconds', example: 42 }),
  page: z.number().int().openapi({ description: 'Current page number of the results', example: 1 }),
  per_page: z.number().int().openapi({ description: 'Number of results per page', example: 20 })
