import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const SeverityEnumSchema = z.enum(['LOW', 'MEDIUM', 'HIGH', 'CRITICAL']).openapi({
  description: 'Nível de severidade da ameaça detectada',
  example: 'CRITICAL'
});

const IPDetailSchema = z.object({
  ip: z.string().ip().openapi({ description: 'Endereço IP do ativo afetado ou do atacante', example: '192.168.1.105' }),
  location: z.string().openapi({ description: 'Localização geográfica associada ao IP', example: 'Brasil' }),
  risk_score: z.number().min(0).max(100).openapi({ description: 'Pontuação de risco de 0 a 100', example: 95 }),
  first_seen: z.string().datetime().openapi({ description: 'Data e hora da primeira detecção', example: '2023-10-27T10:00:00Z' })
}).openapi({ description: 'Detalhes técnicos de um endereço IP afetado' });

const AffectedAssetsSchema = z.object({
  ip_addresses: z.array(IPDetailSchema).openapi({ description: 'Lista de endereços IP envolvidos no incidente' }),
  total_impacted: z.number().int().openapi({ description: 'Quantidade total de ativos impactados', example: 2 })
}).openapi({ description: 'Informações sobre os ativos comprometidos' });

const MitigationStepSchema = z.object({
  step: z.number().int().openapi({ description: 'Ordem sequencial da etapa de mitigação', example: 1 }),
  action: z.string().openapi({ description: 'Descrição detalhada da ação a ser tomada', example: 'Isolar os hosts afetados da rede local' }),
  priority: z.enum(['IMMEDIATE', 'HIGH', 'MEDIUM', 'LOW']).openapi({ description: 'Prioridade de execução da tarefa', example: 'IMMEDIATE' }),
  category: z.string().openapi({ description: 'Categoria da fase de resposta a incidentes', example: 'Containment' })
}).openapi({ description: 'Passo individual do protocolo de mitigação' });

const AlertMetadataSchema = z.object({
  confidence_level: z.enum(['Low', 'Medium', 'High']).openapi({ description: 'Nível de confiança na precisão do alerta', example: 'High' }),
  tlp_classification: z.enum(['WHITE', 'GREEN', 'AMBER', 'RED']).openapi({ description: 'Classificação de compartilhamento de informações (Traffic Light Protocol)', example: 'AMBER' })
}).openapi({ description: 'Metadados de classificação e confiança do alerta' });

export const ThreatIntelligenceAlertSchema = z.object({
  alert_id: z.string().openapi({ description: 'Identificador único do alerta de ameaça', example: 'THREAT-2023-0892' }),
  timestamp: z.string().datetime().openapi({ description: 'Data e hora da emissão do alerta', example: '2023-10-27T14:30:00Z' }),
  severity: SeverityEnumSchema,
  threat_type: z.string().openapi({ description: 'Tipo ou categoria da ameaça', example: 'Ransomware C2 Communication' }),
  source: z.string().openapi({ description: 'Fonte da inteligência de ameaças', example: 'Global Threat Intelligence Feed' }),
  affected_assets: AffectedAssetsSchema,
  mitigation_protocols: z.array(MitigationStepSchema).openapi({ description: 'Lista de protocolos recomendados para neutralizar a ameaça' }),
  metadata: AlertMetadataSchema
}).openapi({
  title: 'Threat Intelligence Alert',
  description: 'Esquema detalhado de um alerta de inteligência de cibersegurança com protocolos de mitigação'
});

