import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const PaymentStatusEnum = z.enum(['PENDING', 'COMPLETED', 'FAILED', 'REFUNDED']).openapi({ 
  description: 'Estado atual da transação financeira' 
});

const RarityEnum = z.enum(['COMMON', 'UNCOMMON', 'RARE', 'EPIC', 'LEGENDARY']).openapi({ 
  description: 'Nível de raridade do item cosmético' 
});

const CosmeticCategoryEnum = z.enum(['SKIN', 'EMOTE', 'AURA', 'PET']).openapi({ 
  description: 'Categoria do item desbloqueado' 
});

const PaymentDetailsSchema = z.object({
  transaction_id: z.string().openapi({ description: 'ID único da transação no provedor de pagamento', example: 'tx_apple_99210' }),
  payment_method: z.string().openapi({ description: 'Método de pagamento utilizado', example: 'Apple Pay' }),
  amount_paid: z.number().openapi({ description: 'Valor total pago pelo usuário', example: 19.99 }),
  currency_code: z.string().openapi({ description: 'Código da moeda ISO 4217', example: 'USD' }),
  status: PaymentStatusEnum
}).openapi({ description: 'Detalhes financeiros da transação' });

const PromoMultiplierSchema = z.object({
  promo_code: z.string().openapi({ description: 'Código promocional aplicado', example: 'FALL_FEST_2023' }),
  multiplier_value: z.number().openapi({ description: 'Fator multiplicador aplicado à quantidade de moeda', example: 1.5 }),
  description: z.string().openapi({ description: 'Descrição legível do bônus aplicado', example: 'Bônus de Outono: 50% a mais de Gemas' })
}).openapi({ description: 'Informações sobre o multiplicador promocional' });

const CurrencyPurchaseSchema = z.object({
  currency_type: z.string().openapi({ description: 'Tipo de moeda virtual adquirida', example: 'GEM' }),
  base_amount: z.number().openapi({ description: 'Quantidade base de moeda sem bônus', example: 1000 }),
  final_amount: z.number().openapi({ description: 'Quantidade final de moeda após multiplicadores', example: 1500 }),
  multiplier_info: PromoMultiplierSchema.optional().openapi({ description: 'Detalhes do multiplicador, se aplicável' })
}).openapi({ description: 'Detalhes da compra de moeda virtual' });

const CosmeticItemSchema = z.object({
  item_id: z.string().openapi({ description: 'Identificador único do item cosmético', example: 'skin_dragon_slayer_01' }),
  name: z.string().openapi({ description: 'Nome exibido do item', example: 'Armadura do Matador de Dragões' }),
  rarity: RarityEnum,
  category: CosmeticCategoryEnum,
  asset_url: z.string().url().openapi({ description: 'URL do recurso visual do item', example: 'https://cdn.game.com/assets/skins/dragon_slayer.png' })
}).openapi({ description: 'Definição de um item cosmético desbloqueado' });

export const MicrotransactionReceiptSchema = z.object({
  receipt_id: z.string().openapi({ description: 'Identificador único do recibo de transação', example: 'rec_88234190234' }),
  user_id: z.string().openapi({ description: 'ID do usuário que realizou a compra', example: 'user_vortex_99' }),
  timestamp: z.string().datetime().openapi({ description: 'Data e hora da transação em formato ISO 8601', example: '2023-10-27T14:30:00Z' }),
  payment_details: PaymentDetailsSchema,
  currency_purchase: CurrencyPurchaseSchema,
  unlocked_cosmetics: z.array(CosmeticItemSchema).openapi({ description: 'Lista de itens cosméticos recebidos como bônus na compra' })
}).openapi({ 
  title: 'Microtransaction Receipt', 
  description: 'Recibo detalhado de microtransação de jogo mobile, incluindo moedas e cosméticos' 
});

